nodes.notes:
Sonarr — TV show library. Use for TV shows, series, and episodes. Not for movies — use radarr for movies.

Actions:
  search — search for a TV show in the library. Use for "is Breaking Bad on Sonarr", "search for Bluey".
  calendar — upcoming episodes airing soon. Use for "what's coming up", "any new episodes this week".
  library — list all series in your library. Use for "what shows do I have", "how many series".
  history — recent download and import activity. Use for "what was recently downloaded", "recent activity".

---schema
{
  "action": {
    "type": "string",
    "description": "One of: calendar, search, library, history",
    "required": true
  },
  "query": {
    "type": "string",
    "description": "TV show name, e.g. Bluey, Breaking Bad. For: search"
  },
  "days": {
    "type": "integer",
    "description": "Calendar lookahead days. Default 7. For: calendar"
  },
  "limit": {
    "type": "integer",
    "description": "Max items to return. Default 20. For: library, history"
  }
}

parameters.jsCode:
// Parse input and extract action + parameters
let data;
const input = $input.item.json;

if (typeof input.body === 'string') {
  data = JSON.parse(input.body);
} else if (typeof input.body === 'object') {
  data = input.body;
} else {
  data = input;
}

const action = (data.action || '').toLowerCase();
const query = data.query || '';
const days = parseInt(data.days) || 7;
const limit = parseInt(data.limit) || 20;

// For calendar, calculate date range
const start = new Date();
start.setHours(0, 0, 0, 0);
const end = new Date(start);
end.setDate(end.getDate() + days);

return [{
  json: {
    action: action,
    query: query,
    queryLower: query.toLowerCase(),
    days: days,
    limit: limit,
    start: start.toISOString().split('T')[0],
    end: end.toISOString().split('T')[0]
  }
}];

// Format calendar for voice
const episodes = $input.all();
const days = $('Parse Parameters').item.json.days;

if (episodes.length === 0) {
  return { message: `No episodes scheduled in the next ${days} days.`, count: 0, episodes: [] };
}

const formatted = episodes.map(item => {
  const ep = item.json;
  const airDate = new Date(ep.airDateUtc);
  const formattedDate = airDate.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' });

  return {
    show: ep.series?.title || ep.seriesTitle || 'Unknown Show',
    season: ep.seasonNumber,
    episode: ep.episodeNumber,
    title: ep.title || 'TBA',
    airDate: formattedDate,
    airDateRaw: ep.airDateUtc,
    hasFile: ep.hasFile || false
  };
});

formatted.sort((a, b) => new Date(a.airDateRaw) - new Date(b.airDateRaw));

let message = '';
if (formatted.length === 1) {
  const ep = formatted[0];
  message = `One episode coming: ${ep.show} season ${ep.season} episode ${ep.episode} on ${ep.airDate}.`;
} else {
  message = `${formatted.length} episodes in the next ${days} days. `;
  const byShow = {};
  formatted.forEach(ep => { if (!byShow[ep.show]) byShow[ep.show] = 0; byShow[ep.show]++; });
  const showSummaries = Object.entries(byShow).slice(0, 4).map(([show, count]) => count === 1 ? show : `${show} (${count} episodes)`);
  message += showSummaries.join(', ');
  if (Object.keys(byShow).length > 4) message += `, and ${Object.keys(byShow).length - 4} more shows.`;
}

return { message, count: formatted.length, episodes: formatted };

const allSeries = $input.all();
const query = $('Parse Parameters').item.json.queryLower;

const matches = allSeries.filter(item => {
  const title = (item.json.title || '').toLowerCase();
  return title.includes(query);
});

if (matches.length === 0) {
  return [{ json: {
    message: `No shows found matching "${$('Parse Parameters').item.json.query}".`,
    found: false,
    shows: []
  }}];
}

const shows = matches.map(item => {
  const s = item.json;
  const stats = s.statistics || {};
  const episodeFileCount = stats.episodeFileCount || 0;
  const totalEpisodeCount = stats.totalEpisodeCount || stats.episodeCount || 0;
  const seasonCount = stats.seasonCount || 0;

  // Figure out which seasons have downloaded episodes
  const seasonsWithFiles = (s.seasons || [])
    .filter(sn => sn.statistics && sn.statistics.episodeFileCount > 0 && sn.seasonNumber > 0)
    .map(sn => sn.seasonNumber);

  return {
    title: s.title,
    year: s.year,
    total_seasons: seasonCount,
    seasons_downloaded: seasonsWithFiles,
    episodes_downloaded: episodeFileCount,
    episodes_total: totalEpisodeCount,
    status: s.status,
    network: s.network || 'Unknown'
  };
});

let message = '';
if (shows.length === 1) {
  const s = shows[0];
  const dl = s.seasons_downloaded;
  if (s.episodes_downloaded === 0) {
    message = `Yes, ${s.title} is in your library but no episodes are downloaded. ${s.total_seasons} season${s.total_seasons !== 1 ? 's' : ''} available.`;
  } else if (dl.length === s.total_seasons) {
    message = `Yes, you have ${s.title}. All ${s.total_seasons} seasons downloaded. ${s.episodes_downloaded} of ${s.episodes_total} episodes.`;
  } else {
    const seasonList = dl.length <= 3 ? dl.join(', ') : dl.slice(0, 3).join(', ') + ` and ${dl.length - 3} more`;
    message = `Yes, you have ${s.title}. Season${dl.length !== 1 ? 's' : ''} ${seasonList} downloaded (${s.episodes_downloaded} episodes). The show has ${s.total_seasons} seasons total.`;
  }
} else {
  message = `Found ${shows.length} shows matching your search. `;
  const preview = shows.slice(0, 3).map(s => s.title);
  message += preview.join(', ');
  if (shows.length > 3) message += `, and ${shows.length - 3} more.`;
}

return [{ json: { message, found: true, count: shows.length, shows } }];

const errorData = $input.item.json;
let errorMsg = errorData.message || errorData.error || 'Unknown error';
if (typeof errorMsg === 'object') {
  errorMsg = errorMsg.message || JSON.stringify(errorMsg);
}
errorMsg = String(errorMsg);

if (errorMsg.includes('401') || errorMsg.includes('403') || errorMsg.includes('Unauthorized')) {
  errorMsg = 'Sonarr authentication failed. Check the API key in n8n.';
} else if (errorMsg.includes('ECONNREFUSED') || errorMsg.includes('ETIMEDOUT')) {
  errorMsg = 'Cannot connect to Sonarr. Is it running?';
} else if (errorMsg.includes('Credential')) {
  errorMsg = 'Sonarr credentials not found in n8n.';
}

return [{ json: { message: `Error with Sonarr: ${errorMsg}`, error: true } }];

// Format library summary for voice
const allSeries = $input.all();
const limit = $('Parse Parameters').item.json.limit;

const totalSeries = allSeries.length;
let totalEpisodes = 0;
let totalMonitored = 0;

const series = allSeries.map(item => {
  const s = item.json;
  const episodes = s.statistics?.episodeFileCount || 0;
  totalEpisodes += episodes;
  if (s.monitored) totalMonitored++;

  return {
    title: s.title,
    seasons: s.statistics?.seasonCount || 0,
    episodes: episodes,
    status: s.status || 'unknown',
    monitored: s.monitored || false
  };
});

// Sort alphabetically and limit
series.sort((a, b) => a.title.localeCompare(b.title));
const limited = series.slice(0, limit);

let message = `You have ${totalSeries} series in your library. ${totalMonitored} are monitored.`;
if (totalSeries > 0) {
  const preview = limited.slice(0, 5).map(s => s.title).join(', ');
  message += ` Including: ${preview}`;
  if (totalSeries > 5) message += `, and ${totalSeries - 5} more.`;
}

return { message, count: totalSeries, monitored: totalMonitored, series: limited };

const input = $input.item.json;
const records = input.records || [];
const limit = $('Parse Parameters').item.json.limit;

const eventTypeMap = {
  'grabbed': 'Grabbed',
  'downloadFolderImported': 'Imported',
  'episodeFileDeleted': 'Deleted',
  'downloadFailed': 'Failed',
  'episodeFileRenamed': 'Renamed',
  'seriesFolderImported': 'Imported'
};

const history = records.slice(0, limit).map(r => {
  const series = r.series?.title || 'Unknown';
  const season = r.episode?.seasonNumber || 0;
  const episode = r.episode?.episodeNumber || 0;
  const epTitle = r.episode?.title || '';
  const quality = r.quality?.quality?.name || 'Unknown';
  const event = eventTypeMap[r.eventType] || r.eventType || 'Unknown';
  const date = r.date ? new Date(r.date).toLocaleDateString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' }) : 'Unknown';

  return {
    series,
    season,
    episode,
    episode_title: epTitle,
    quality,
    event,
    date
  };
});

if (history.length === 0) {
  return [{ json: { message: 'No recent activity in Sonarr.', count: 0, history: [] } }];
}

const lines = history.slice(0, 5).map((h, i) => {
  const ep = `S${String(h.season).padStart(2, '0')}E${String(h.episode).padStart(2, '0')}`;
  return `${i + 1}. ${h.event} ${h.series} ${ep} in ${h.quality}`;
});
let message = 'Recent activity: ' + lines.join('. ') + '.';
if (history.length > 5) message += ` And ${history.length - 5} more.`;

return [{ json: { message, count: history.length, history } }];
